import React, { useEffect, useState } from "react";
import axios from "axios";

export default function ListaPeriodos({ onEditar }) {
  const [periodos, setPeriodos] = useState([]);
  const [carregando, setCarregando] = useState(true);

useEffect(() => {
  setCarregando(true);
  axios
    .get("/api/periodos")
    .then((res) => {
      setPeriodos(res.data);
      setCarregando(false);
    })
    .catch(() => setCarregando(false));
}, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm("Tem certeza que deseja deletar este período?")) {
      axios
        .delete(`/api/periodos/${id}`)
        .then(() => setPeriodos(periodos.filter((p) => p.id !== id)));
    }
  };

  if (carregando) return <p>Carregando períodos...</p>;
  if (periodos.length === 0) return <p>Nenhum período cadastrado.</p>;

  return (
    <table className="min-w-full rounded-xl">
      <thead>
        <tr className="border-b bg-gray-100">
          <th className="px-4 py-2 text-left">Nome</th>
          <th className="px-4 py-2 text-left">Turno</th>
          <th className="px-4 py-2"></th>
        </tr>
      </thead>
      <tbody>
        {periodos.map((p) => (
          <tr key={p.id} className="border-b hover:bg-gray-50">
            <td className="px-4 py-2">{p.nome}</td>
            <td className="px-4 py-2">{p.turno}</td>
            <td className="px-4 py-2 flex gap-2">
              <button
                className="bg-blue-500 text-white px-3 py-1 rounded"
                onClick={() => onEditar && onEditar(p)}
              >
                Editar
              </button>
              <button
                className="bg-red-500 text-white px-3 py-1 rounded"
                onClick={() => handleDeletar(p.id)}
              >
                Deletar
              </button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}
